/* eslint-disable react/no-unknown-property */
/** @jsxRuntime classic */
/** @jsx jsx */
/** @jsxFrag React.Fragment */
import { jsx, useMergeComponentProps } from '@universe-design/stylex/react';
import React from 'react';
import stylex from '@universe-design/stylex';
import clsx from 'clsx';
import type { HTMLProps } from 'react';
import { useOverflowContext } from '../overflow/hooks';
import { useTabsContext } from './TabsContext';
import { forwardHTMLRef } from '../util/forwardRef';
import { Text } from '../text';
import { sxTabSize, sxTabTypography, useTabStyles } from './sx';
import { useTabContext } from './TabContext';
import type { StylexProps } from '../util';

export const Tab = (props: StylexProps & Pick<HTMLProps<HTMLDivElement>, 'onClick'>) => {
  const {
    size,
    panes,
    rootCssScope,
    type,
    tabBarGutter,
    handleTabClick,
    handleTabDoubleClick,
    activeTabIndex,
    activeKey,
    tabElementMapRef,
  } = useTabsContext();
  const tabStyles = useTabStyles({ prefix: rootCssScope() });
  const { key } = useTabContext();
  const { omittedKeys } = useOverflowContext();
  const paneProps = panes.find(p => p.key === key);
  const paneIndex = panes.findIndex(p => p.key === key);
  if (!paneProps) {
    return null;
  }
  const { tab, disabled } = paneProps;
  const isActive = paneIndex === activeTabIndex;
  const cls = clsx(
    rootCssScope('__tab'),
    rootCssScope(`__tab--${type}`),
    {
      [rootCssScope('__tab--active')]: isActive,
      [rootCssScope('__tab--divider')]:
        type === 'card' &&
        (paneIndex < activeTabIndex - 1 ||
          paneIndex > activeTabIndex ||
          (paneIndex === activeTabIndex - 1 && omittedKeys.includes(activeKey))),
      [rootCssScope('__tab--disabled')]: disabled,
    },
    type === 'tag' && {
      [rootCssScope('-sm-border-radius')]: true,
      [rootCssScope('-neutral-background')]: !isActive,
      [rootCssScope('-primary-background')]: isActive,
      [rootCssScope('-color-pri-text')]: isActive,
    },
  );

  return (
    <div
      ref={node => {
        tabElementMapRef.current?.set(key, node);
      }}
      style={{
        ...(type === 'line' ? { marginRight: tabBarGutter } : {}),
      }}
      className={cls}
      key={`tab-nav-key-${paneIndex}`}
      data-testid="ud__tab-bar"
      onClick={e => {
        props.onClick?.(e);
        handleTabClick(key, e);
      }}
      onDoubleClick={e => handleTabDoubleClick(key, e)}
      sx={[
        type !== 'capsule' && tabStyles.tabHover,
        sxTabTypography(size, isActive),
        sxTabSize(type, size),
        type === 'card' && [tabStyles.cardBase, isActive ? tabStyles.cardActive : tabStyles.cardDefault],
        type === 'capsule' && [tabStyles.capsuleBase, isActive ? tabStyles.capsuleActive : tabStyles.capsuleDefault],
        props.sx,
      ]}
    >
      {tab}
    </div>
  );
};

// 因为外层 TabItem 是 flex，没法使用 Text，用这个做单行省略
export const TabContent = forwardHTMLRef<unknown, 'span'>((props, ref) => {
  const { isOmitted } = useTabContext();
  return (
    <Text
      as="span"
      lineClamp={isOmitted ? undefined : 1}
      ref={ref}
      {...useMergeComponentProps(props, {
        sx: [stylex.create({ minWidth: 20 })],
      })}
    />
  );
});
